mapper.insert:
INSERT INTO attendance_record (
    employee_id, attendance_date, clock_in_time, attendance_status
) VALUES (
    #{employeeId}, #{attendanceDate}, #{clockInTime}, #{attendanceStatus}
)

mapper.update:
UPDATE attendance_record
SET clock_out_time = #{clockOutTime}, updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}

mapper.insert:
INSERT INTO attendance_makeup_quota (
    employee_id, quota_month, total_count, used_count, assigned_by
) VALUES (
    #{employeeId}, #{quotaMonth}, #{totalCount}, #{usedCount}, #{assignedBy}
)
ON DUPLICATE KEY UPDATE
    total_count = #{totalCount},
    assigned_by = #{assignedBy},
    updated_at = CURRENT_TIMESTAMP

mapper.update:
UPDATE attendance_makeup_quota
SET used_count = used_count + 1,
    updated_at = CURRENT_TIMESTAMP
WHERE employee_id = #{employeeId}
  AND quota_month = #{quotaMonth}
  AND used_count < total_count

mapper.select:
SELECT id, application_id, attendance_record_id, employee_id, quota_month, created_at
FROM attendance_makeup_usage
WHERE application_id = #{applicationId}

mapper.insert:
